     1→package handlers
     2→
     3→import (
     4→	"context"
     5→	"fmt"
     6→	"io"
     7→	"net/http"
     8→	"strconv"
     9→
    10→	iafv1alpha1 "github.com/dlapiduz/iaf/api/v1alpha1"
    11→	"github.com/dlapiduz/iaf/internal/auth"
    12→	"github.com/labstack/echo/v4"
    13→	corev1 "k8s.io/api/core/v1"
    14→	apierrors "k8s.io/apimachinery/pkg/api/errors"
    15→	"k8s.io/apimachinery/pkg/types"
    16→	"k8s.io/client-go/kubernetes"
    17→	"sigs.k8s.io/controller-runtime/pkg/client"
    18→)
    19→
    20→type LogsHandler struct {
    21→	client    client.Client
    22→	clientset kubernetes.Interface
    23→	sessions  *auth.SessionStore
    24→}
    25→
    26→func NewLogsHandler(c client.Client, cs kubernetes.Interface, sessions *auth.SessionStore) *LogsHandler {
    27→	return &LogsHandler{
    28→		client:    c,
    29→		clientset: cs,
    30→		sessions:  sessions,
    31→	}
    32→}
    33→
    34→func (h *LogsHandler) resolveNamespace(c echo.Context) (string, error) {
    35→	sessionID := c.Request().Header.Get("X-IAF-Session")
    36→	if sessionID == "" {
    37→		sessionID = c.QueryParam("session_id")
    38→	}
    39→	if sessionID == "" {
    40→		return "", fmt.Errorf("missing session ID: provide X-IAF-Session header or session_id query parameter")
    41→	}
    42→	sess, ok := h.sessions.Lookup(sessionID)
    43→	if !ok {
    44→		return "", fmt.Errorf("session not found, call register first")
    45→	}
    46→	return sess.Namespace, nil
    47→}
    48→
    49→// GetLogs returns logs for an application's pods.
    50→func (h *LogsHandler) GetLogs(c echo.Context) error {
    51→	namespace, err := h.resolveNamespace(c)
    52→	if err != nil {
    53→		return c.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
    54→	}
    55→
    56→	name := c.Param("name")
    57→	lines := int64(100)
    58→	if l := c.QueryParam("lines"); l != "" {
    59→		if parsed, err := strconv.ParseInt(l, 10, 64); err == nil {
    60→			lines = parsed
    61→		}
    62→	}
    63→
    64→	// Verify application exists
    65→	var app iafv1alpha1.Application
    66→	if err := h.client.Get(c.Request().Context(), types.NamespacedName{Name: name, Namespace: namespace}, &app); err != nil {
    67→		if apierrors.IsNotFound(err) {
    68→			return c.JSON(http.StatusNotFound, map[string]string{"error": "application not found"})
    69→		}
    70→		return c.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
    71→	}
    72→
    73→	// Get pods for the application
    74→	podList := &corev1.PodList{}
    75→	if err := h.client.List(c.Request().Context(), podList,
    76→		client.InNamespace(namespace),
    77→		client.MatchingLabels{"iaf.io/application": name},
    78→	); err != nil {
    79→		return c.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
    80→	}
    81→
    82→	if len(podList.Items) == 0 {
    83→		return c.JSON(http.StatusOK, map[string]any{
    84→			"logs": "",
    85→			"pods": 0,
    86→		})
    87→	}
    88→
    89→	// Get logs from the first pod
    90→	pod := podList.Items[0]
    91→	logs, err := h.getPodLogs(c.Request().Context(), namespace, pod.Name, "app", lines)
    92→	if err != nil {
    93→		return c.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
    94→	}
    95→
    96→	return c.JSON(http.StatusOK, map[string]any{
    97→		"logs":    logs,
    98→		"pods":    len(podList.Items),
    99→		"podName": pod.Name,
   100→	})
   101→}
   102→
   103→// GetBuildLogs returns kpack build logs for an application.
   104→func (h *LogsHandler) GetBuildLogs(c echo.Context) error {
   105→	namespace, err := h.resolveNamespace(c)
   106→	if err != nil {
   107→		return c.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
   108→	}
   109→
   110→	name := c.Param("name")
   111→
   112→	// Verify application exists
   113→	var app iafv1alpha1.Application
   114→	if err := h.client.Get(c.Request().Context(), types.NamespacedName{Name: name, Namespace: namespace}, &app); err != nil {
   115→		if apierrors.IsNotFound(err) {
   116→			return c.JSON(http.StatusNotFound, map[string]string{"error": "application not found"})
   117→		}
   118→		return c.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
   119→	}
   120→
   121→	// Look for kpack build pods
   122→	podList := &corev1.PodList{}
   123→	if err := h.client.List(c.Request().Context(), podList,
   124→		client.InNamespace(namespace),
   125→		client.MatchingLabels{"image.kpack.io/image": name},
   126→	); err != nil {
   127→		return c.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
   128→	}
   129→
   130→	if len(podList.Items) == 0 {
   131→		return c.JSON(http.StatusOK, map[string]any{
   132→			"buildLogs":   "",
   133→			"buildStatus": app.Status.BuildStatus,
   134→		})
   135→	}
   136→
   137→	// Get logs from the most recent build pod
   138→	pod := podList.Items[len(podList.Items)-1]
   139→	var allLogs string
   140→	for _, container := range pod.Spec.InitContainers {
   141→		logs, err := h.getPodLogs(c.Request().Context(), namespace, pod.Name, container.Name, 200)
   142→		if err != nil {
   143→			continue
   144→		}
   145→		allLogs += fmt.Sprintf("=== %s ===\n%s\n", container.Name, logs)
   146→	}
   147→
   148→	return c.JSON(http.StatusOK, map[string]any{
   149→		"buildLogs":   allLogs,
   150→		"buildStatus": app.Status.BuildStatus,
   151→		"podName":     pod.Name,
   152→	})
   153→}
   154→
   155→func (h *LogsHandler) getPodLogs(ctx context.Context, namespace, podName, container string, lines int64) (string, error) {
   156→	opts := &corev1.PodLogOptions{
   157→		Container: container,
