			"name":          input.Name,
			"logs":          string(data),
			"podName":       pod.Name,
			"availablePods": availablePods,
			"phase":         string(app.Status.Phase),
		}

		text, _ := json.MarshalIndent(result, "", "  ")
		return &gomcp.CallToolResult{
			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
		}, nil, nil
