	*k8sfake.Clientset
	logsByPod map[string]string // pod name -> log content
}

func (f *fakeLogClientset) CoreV1() corev1client.CoreV1Interface {
	return &fakeCore{CoreV1Interface: f.Clientset.CoreV1(), logsByPod: f.logsByPod}
}

type fakeCore struct {
	corev1client.CoreV1Interface
	logsByPod map[string]string
}

func (fc *fakeCore) Pods(namespace string) corev1client.PodInterface {
	return &fakePodClient{PodInterface: fc.CoreV1Interface.Pods(namespace), logsByPod: fc.logsByPod}
}

type fakePodClient struct {
	corev1client.PodInterface
	logsByPod map[string]string
}

func (fp *fakePodClient) GetLogs(name string, opts *corev1.PodLogOptions) *rest.Request {
	// Return a request that streams the fake log content.
	// We return the base request but override the stream via the RESTClient.
	// Since we can't easily intercept rest.Request, we use a simpler approach:
	// build a fake request by embedding the pod client's request but returning a passthrough.
	// For testing purposes we rely on the base fake clientset; actual log content
	// won't stream, so we test the pod selection logic separately via the k8s helper tests.
	return fp.PodInterface.GetLogs(name, opts)
}

// setupLogsServer creates an MCP server with app_logs registered using a fake clientset.
// It returns the MCP client session, the auth session store, and the fake k8s clients.
func setupLogsServer(t *testing.T, objs ...runtime.Object) (
	*gomcp.ClientSession,
	*auth.SessionStore,
	*fake.ClientBuilder,
) {
	t.Helper()
	ctx := context.Background()

	scheme := runtime.NewScheme()
	_ = iafv1alpha1.AddToScheme(scheme)
	_ = corev1.AddToScheme(scheme)

	builder := fake.NewClientBuilder().WithScheme(scheme)
	k8sClient := builder.Build()

	store, err := sourcestore.New(t.TempDir(), "http://localhost:8080", slog.Default())
	if err != nil {
		t.Fatal(err)
	}

	sessions, err := auth.NewSessionStore(filepath.Join(t.TempDir(), "sessions.json"))
	if err != nil {
		t.Fatal(err)
	}

	deps := &tools.Dependencies{
		Client:     k8sClient,
		Store:      store,
		BaseDomain: "test.example.com",
		Sessions:   sessions,
	}

	clientset := k8sfake.NewSimpleClientset()

	server := gomcp.NewServer(&gomcp.Implementation{Name: "test", Version: "0.0.1"}, nil)
	tools.RegisterRegisterTool(server, deps)
	tools.RegisterAppLogsWithClientset(server, deps, clientset)

	st, ct := gomcp.NewInMemoryTransports()
	if _, err := server.Connect(ctx, st, nil); err != nil {
		t.Fatal(err)
	}
	client := gomcp.NewClient(&gomcp.Implementation{Name: "test-client", Version: "0.0.1"}, nil)
	cs, err := client.Connect(ctx, ct, nil)
	if err != nil {
		t.Fatal(err)
	}
	t.Cleanup(func() { cs.Close() })
	return cs, sessions, builder
}

func makePodForApp(name, namespace, appName string, createdAt time.Time) *corev1.Pod {
	return &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
