		},
		Spec: iafv1alpha1.ApplicationSpec{
			Image: "nginx:latest",
		},
		Status: iafv1alpha1.ApplicationStatus{
			Phase: iafv1alpha1.PhaseRunning,
		},
	}
}

// registerAndGetSession calls the register tool and returns the session ID and namespace.
func registerAndGetSession(t *testing.T, cs *gomcp.ClientSession, agentName string) (string, string) {
	t.Helper()
	res, err := cs.CallTool(context.Background(), &gomcp.CallToolParams{
		Name:      "register",
