	cs, err := mcpClient.Connect(ctx, ct, nil)
	if err != nil {
		t.Fatal(err)
	}
	t.Cleanup(func() { cs.Close() })

	// Requesting logs from a pod belonging to a different app should fail
	res, err := cs.CallTool(ctx, &gomcp.CallToolParams{
		Name: "app_logs",
		Arguments: map[string]any{
			"session_id": sid,
			"name":       "myapp",
			"pod_name":   "otherapp-pod",
		},
	})
	if err != nil {
		t.Fatal(err)
	}
	if !res.IsError {
		t.Error("expected error when specifying pod from a different app (cross-app access denied)")
	}
