package tools

import (
	"context"
	"fmt"

	iafv1alpha1 "github.com/dlapiduz/iaf/api/v1alpha1"
	"github.com/dlapiduz/iaf/internal/auth"
	iafgithub "github.com/dlapiduz/iaf/internal/github"
	"github.com/dlapiduz/iaf/internal/orgstandards"
	"github.com/dlapiduz/iaf/internal/sourcestore"
	"sigs.k8s.io/controller-runtime/pkg/client"
)

// Dependencies holds shared dependencies for MCP tools.
type Dependencies struct {
	Client       client.Client
	Store        *sourcestore.Store
	BaseDomain   string
	Sessions     *auth.SessionStore
	OrgStandards *orgstandards.Loader
	// GitHub fields — all three must be set for GitHub tools to be registered.
	GitHub      iafgithub.Client
	GitHubToken string // stored but never surfaced in output or logs
	GitHubOrg   string
	// Observability standards — optional override file paths.
	// When empty the embedded defaults in config/org-standards/*.json are used.
	LoggingStandardsFile string
	MetricsStandardsFile string
	TracingStandardsFile string
	// TempoURL is the Grafana base URL used to build traceExploreUrl in
	// app_status responses. Set from IAF_TEMPO_URL. Empty = feature disabled.
	TempoURL string
}

// ResolveNamespace looks up the session and returns its namespace.
func (d *Dependencies) ResolveNamespace(sessionID string) (string, error) {
	sess, ok := d.Sessions.Lookup(sessionID)
	if !ok {
		return "", fmt.Errorf("session not found, call the register tool first")
	}
	return sess.Namespace, nil
}

// CheckAppNameAvailable verifies that no application with the given name exists
// in any other namespace. This prevents hostname collisions since all apps
// share the same base domain regardless of namespace.
func (d *Dependencies) CheckAppNameAvailable(ctx context.Context, appName, currentNamespace string) error {
	var allApps iafv1alpha1.ApplicationList
	if err := d.Client.List(ctx, &allApps); err != nil {
		return fmt.Errorf("checking application name availability: %w", err)
	}
	for _, app := range allApps.Items {
		if app.Name == appName && app.Namespace != currentNamespace {
			return fmt.Errorf("application name %q is already in use in namespace %q — choose a different name", appName, app.Namespace)
		}
	}
	return nil
}

package tools

import (
	"context"
	"encoding/json"
	"fmt"

	"github.com/dlapiduz/iaf/internal/auth"
	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
)

type RegisterInput struct {
	Name string `json:"name,omitempty" jsonschema:"optional friendly name for your workspace (e.g. 'my-project')"`
}

func RegisterRegisterTool(server *gomcp.Server, deps *Dependencies) {
	gomcp.AddTool(server, &gomcp.Tool{
		Name:        "register",
		Description: "CALL THIS FIRST. Creates a new session and returns a session_id that is required by every other tool. You only need to call this once — store the session_id and pass it to all subsequent tool calls. Optionally provide a friendly name for your workspace.",
	}, func(ctx context.Context, req *gomcp.CallToolRequest, input RegisterInput) (*gomcp.CallToolResult, any, error) {
		sess, err := deps.Sessions.Register(input.Name)
		if err != nil {
			return nil, nil, fmt.Errorf("registering session: %w", err)
		}

		if err := auth.EnsureNamespace(ctx, deps.Client, sess.Namespace); err != nil {
			return nil, nil, fmt.Errorf("creating namespace: %w", err)
		}

		result := map[string]any{
			"session_id": sess.ID,
			"namespace":  sess.Namespace,
			"message":    "Session created. IMPORTANT: Store this session_id and include it in ALL subsequent tool calls as the session_id parameter.",
		}

		text, _ := json.MarshalIndent(result, "", "  ")
		return &gomcp.CallToolResult{
			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
		}, nil, nil
	})
}

package config

import (
	"strings"

	"github.com/spf13/viper"
)

// Config holds all configuration for IAF components.
type Config struct {
	// API server settings
	APIPort   int      `mapstructure:"api_port"`
	APITokens []string `mapstructure:"api_tokens"`

	// MCP server settings
	MCPTransport string `mapstructure:"mcp_transport"` // "stdio" or "http"
	MCPPort      int    `mapstructure:"mcp_port"`

	// Kubernetes settings
	DefaultNamespace string `mapstructure:"default_namespace"`
	KubeConfig       string `mapstructure:"kubeconfig"`

	// kpack settings
	ClusterBuilder string `mapstructure:"cluster_builder"`
	RegistryPrefix string `mapstructure:"registry_prefix"`

	// Source store settings
	SourceStoreDir string `mapstructure:"source_store_dir"`
	SourceStoreURL string `mapstructure:"source_store_url"`

	// Routing
	BaseDomain string `mapstructure:"base_domain"`
	// TLSIssuer is the ClusterIssuer name for cert-manager. Default: "selfsigned-issuer".
	// Set to "" to disable TLS certificate provisioning (e.g., cert-manager not installed).
	TLSIssuer string `mapstructure:"tls_issuer"`

	// Org standards
	OrgStandardsFile string `mapstructure:"org_standards_file"`

	// GitHub integration (optional — GitHub features are disabled when token is empty)
	GitHubToken string `mapstructure:"github_token"`
	GitHubOrg   string `mapstructure:"github_org"`

	// Observability (optional — features are disabled when URLs are empty)
	// TempoURL is the Grafana base URL for trace explore links (IAF_TEMPO_URL).
	TempoURL string `mapstructure:"tempo_url"`
}

// Load reads configuration from environment variables and defaults.
func Load() (*Config, error) {
	v := viper.New()

	v.SetDefault("api_port", 8080)
	v.SetDefault("api_tokens", []string{"iaf-dev-key"})
	v.SetDefault("mcp_transport", "stdio")
	v.SetDefault("mcp_port", 8081)
	v.SetDefault("default_namespace", "iaf-apps")
	v.SetDefault("cluster_builder", "iaf-cluster-builder")
	v.SetDefault("registry_prefix", "registry.localhost:5000/iaf")
	v.SetDefault("source_store_dir", "/tmp/iaf-sources")
	v.SetDefault("source_store_url", "http://iaf-source-store.iaf-system.svc.cluster.local")
	v.SetDefault("base_domain", "localhost")
	v.SetDefault("tls_issuer", "")
	v.SetDefault("org_standards_file", "")
	v.SetDefault("github_token", "")
	v.SetDefault("github_org", "")
	v.SetDefault("tempo_url", "")

	v.SetEnvPrefix("IAF")
	v.SetEnvKeyReplacer(strings.NewReplacer(".", "_"))
	v.AutomaticEnv()

	cfg := &Config{}
	if err := v.Unmarshal(cfg); err != nil {
		return nil, err
	}
	return cfg, nil
}

